class User_Model_UserSettings extends User_Model_Base_UserSettings {

    /**
     * @param int $userID
     * @return self|null
     */
    public static function getUserSettings(int $userID): ?self {
        $query = Doctrine_Query::create();
        $query->from('User_Model_UserSettings object');
        $query->leftJoin('object.users users');
